const baseUrl = ($env.BACKEND_API_URL || 'http://backend:8000').replace(/\/$/, '');
const username = $env.CAMPAIGN_LINKER_USERNAME || 'analyst';
const password = $env.CAMPAIGN_LINKER_PASSWORD || 'analyst123';

const login = await this.helpers.httpRequest({
  method: 'POST',
  url: `${baseUrl}/auth/login`,
  body: {
    username,
    password,
    workspace: 'dashboard'
  },
  json: true
});

const summary = await this.helpers.httpRequest({
  method: 'POST',
  url: `${baseUrl}/campaigns/link-events`,
  headers: {
    Authorization: `Bearer ${login.access_token}`
  },
  json: true
});

return [
  {
    json: {
      ran_at: new Date().toISOString(),
      workflow: 'Campaign Event Linking',
      ...summary
    }
  }
];
